code = """import json
import pandas as pd

# Load the full datasets
childrens_books_file = locals()['var_functions.query_db:16']
reviews_2020_file = locals()['var_functions.query_db:14']

with open(childrens_books_file, 'r') as f:
    childrens_books = json.load(f)

with open(reviews_2020_file, 'r') as f:
    reviews_2020 = json.load(f)

# Convert to DataFrames
books_df = pd.DataFrame(childrens_books)
reviews_df = pd.DataFrame(reviews_2020)

# Clean and convert rating to numeric
reviews_df['rating'] = pd.to_numeric(reviews_df['rating'], errors='coerce')

# Join on book_id = purchase_id
merged_df = reviews_df.merge(books_df, left_on='purchase_id', right_on='book_id', how='inner')

# Group by book and calculate avg rating
grouped = merged_df.groupby(['book_id', 'title'])['rating'].agg(['mean', 'count']).reset_index()

# Rename columns
grouped.columns = ['book_id', 'title', 'avg_rating', 'review_count']

# Filter for avg rating >= 4.5
high_rated_books = grouped[grouped['avg_rating'] >= 4.5].copy()

# Sort by avg rating desc, then review count desc
high_rated_books = high_rated_books.sort_values(['avg_rating', 'review_count'], ascending=[False, False])

print('__RESULT__:')
print(json.dumps({
    'books': high_rated_books.to_dict('records'),
    'total_books': len(high_rated_books)
}))"""

